import React from 'react';

const RateCard = ({ currency, index }) => {
    const formatNumber = (num) => {
        return num ? num.toFixed(4) : '0.0000';
    };

    return (
        <div className="rate-card" style={{ animationDelay: `${index * 0.05}s` }}>
            <div className="rate-card-header">
                <div className="currency-icon">
                    <i className={`fas ${currency.icon || 'fa-money-bill-wave'}`}></i>
                </div>
                <div className="currency-info">
                    <div className="currency-name">{currency.name}</div>
                    <div className="currency-code">{currency.code}</div>
                </div>
                <div className="trend-icon">
                    <i className="fas fa-chart-line"></i>
                </div>
            </div>
            
            <div className="rate-card-body">
                <div className="rate-item">
                    <div className="rate-label"><i className="fas fa-arrow-up"></i> SELLING</div>
                    <div className="rate-value sell-rate">{formatNumber(currency.sell_rate)}</div>
                </div>
                <div className="rate-divider"></div>
                <div className="rate-item">
                    <div className="rate-label"><i className="fas fa-arrow-down"></i> BUYING</div>
                    <div className="rate-value buy-rate">{formatNumber(currency.buy_rate)}</div>
                </div>
            </div>
            
            <div className="rate-card-footer">
                <span>ETB per unit</span>
                <i className="fas fa-chart-simple"></i>
            </div>
        </div>
    );
};

export default RateCard;
